+++ b/src/ipc/libmultiprocess/include/mp/proxy.h
@@ -68,10 +68,15 @@ public:
 struct ProxyContext
 {
     Connection* connection;
     EventLoopRef loop;
     CleanupList cleanup_fns;
+#ifndef NDEBUG
+    //! Hook called on the worker thread just before loop->sync() in PassField
